def _block_ready(x):
    jax.tree_util.tree_map(jax.block_until_ready, x)
    return x


def _normalise_memory_value(value):
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _snapshot_device_memory():
    stats = {}
    for i, device in enumerate(jax.devices()):
        device_stats_fn = getattr(device, "memory_stats", None)
        if device_stats_fn is None:
            continue
        try:
            device_stats = device_stats_fn()
        except Exception:
            continue
        if not device_stats:
            continue
        stats[f"device{i}"] = {
            key: _normalise_memory_value(value)
            for key, value in device_stats.items()
        }
    return stats or None


def benchmark_jax_call(
    fn, *, warmup=0, repeat=5, track_memory=False, track_device_memory=False
):
    for _ in range(warmup):
        _block_ready(fn())

    times = []
    peak_memories = []
    device_memory = []

    for _ in range(repeat):
        gc.collect()
        if track_memory:
            tracemalloc.start()
        before_device_memory = (
            _snapshot_device_memory() if track_device_memory else None
        )

        t0 = perf_counter()
        out = fn()
        _block_ready(out)
        dt = perf_counter() - t0
        times.append(dt)

        if track_memory:
            _, peak = tracemalloc.get_traced_memory()
            peak_memories.append(peak)
            tracemalloc.stop()
        if track_device_memory:
            device_memory.append(
                {
                    "before": before_device_memory,
                    "after": _snapshot_device_memory(),
                }
            )

    result = {
        "last_output": out,
        "times": np.array(times),
        "mean_time": float(np.mean(times)),
        "min_time": float(np.min(times)),
        "std_time": float(np.std(times)),
    }
    if track_memory:
        result["peak_host_memory_bytes"] = int(np.max(peak_memories))
    if track_device_memory:
        result["device_memory"] = device_memory

    return result


def _format_device_memory(bench):
    snapshots = bench.get("device_memory")
    if not snapshots:
        return None

    last = snapshots[-1]
    after = last.get("after") or {}
    fragments = []
    for device_name, stats in after.items():
        bytes_in_use = stats.get("bytes_in_use")
        peak_bytes = (
            stats.get("peak_bytes_in_use")
            if stats.get("peak_bytes_in_use") is not None
            else stats.get("bytes_limit")
        )
        parts = [device_name]
        if bytes_in_use is not None:
            parts.append(f"used={bytes_in_use / 1024**2:.2f} MiB")
        if peak_bytes is not None:
            parts.append(f"peak={peak_bytes / 1024**2:.2f} MiB")
        if len(parts) > 1:
            fragments.append(",".join(parts))
    return " | ".join(fragments) if fragments else None


def _stats_line(label, bench, *, include_memory=False, include_device_memory=False):
    line = (
        f"{label}:"
        f" mean={bench['mean_time']:.6f} s"
        f" min={bench['min_time']:.6f} s"
        f" std={bench['std_time']:.6f} s"
    )
    if include_memory:
        line += f" peak_host_mem={bench['peak_host_memory_bytes'] / 1024**2:.2f} MiB"
    if include_device_memory:
        device_line = _format_device_memory(bench)
        if device_line is not None:
            line += f" device_mem=[{device_line}]"
    return line


def _tree_l2_norm(tree):
    leaves = jax.tree_util.tree_leaves(tree)
    if not leaves:
        return 0.0
    return float(jnp.sqrt(sum(jnp.sum(jnp.abs(x) ** 2) for x in leaves)))


def _tree_diff_l2_norm(tree_a, tree_b):
    diff = jax.tree_util.tree_map(lambda a, b: a - b, tree_a, tree_b)
    return _tree_l2_norm(diff)

