###############################################################
print(20*'#', 'NOW doing TDVP', 20*'#')
import netket.experimental as nkx
integrator = nkx.dynamics.RK4(dt=1e-2)

# solvers
QGT = nk.optimizer.qgt.QGTJacobianDense(diag_shift=1e-4, holomorphic=True)
linear_solver = nk.optimizer.solver.pinv_smooth( rtol=1e-4, rtol_smooth=0 ) #rtol=1e-7 for T=7, 

from netket.experimental.driver.tdvp_common import TDVPBaseDriver, odefun
from netket.experimental.driver.tdvp import TDVP, _map_parameters, tree_cast

variables = vs.variables
for case in [0,1]:
    vs.variables = variables
    vs.reset()
    @odefun.dispatch(precedence=10)
    def odefun_tdvp(  # noqa: F811
        state: nk.vqs.MCState, driver: TDVP, t, w, *, stage=0
    ):
        # pylint: disable=protected-access

        state.parameters = w
        state.reset()

        # op_t = driver.generator(t)

        if case==0:
            driver._loss_stats, driver._loss_forces = driver.generator.expect_and_forces(
                t, state
            )
        else:
            driver._loss_stats, driver._loss_forces = state.expect_and_forces(
                driver.generator(t)
            )
        driver._loss_grad = _map_parameters(
            driver._loss_forces,
            state.parameters,
            driver._loss_grad_factor,
            driver.propagation_type,
            type(state),
        )

        qgt = driver.qgt(driver.state)
        if stage == 0:  # TODO: This does not work with FSAL.
            driver._last_qgt = qgt

        initial_dw = None if driver.linear_solver_restart else driver._dw
        driver._dw, _ = qgt.solve(driver.linear_solver, driver._loss_grad, x0=initial_dw)

        # If parameters are real, then take only real part of the gradient (if it's complex)
        driver._dw = tree_cast(driver._dw, state.parameters)

        return driver._dw

    # driver
    te = nkx.TDVP(
        Ham,
        variational_state=vs,
        ode_solver=integrator,
        t0=0,
        qgt=QGT,
        linear_solver=linear_solver
    )


    times = np.linspace(t,T,int((T-t)/1e-2)+1)
    # perform the time-evolution saving the observable at every `tstop` time
    t0 = time.time()
    te.run(
        T=T,
        show_progress=True,
        tstops=times
    )

    print('Total time: ', time.time()-t0)